const clientId = 'YOUR_CLIENT_ID';
const redirectUri = 'YOUR_REDIRECT_URI';
const authEndpoint = 'https://authorization-server.com/auth';
const apiEndpoint = 'https://api-server.com/resource';
const scope = 'YOUR_SCOPES';

function redirectToAuth() {
    const url = `${authEndpoint}?response_type=token&client_id=${clientId}&redirect_uri=${encodeURIComponent(redirectUri)}&scope=${encodeURIComponent(scope)}`;
    window.location.href = url;
}

function parseAccessToken() {
    const hash = window.location.hash;
    if (hash) {
        const params = new URLSearchParams(hash.substring(1));
        const accessToken = params.get('access_token');
        if (accessToken) {
            sessionStorage.setItem('access_token', accessToken);
            window.location.hash = ''; // Clear the hash
            return accessToken;
        }
    }
    return null;
}

function apiCall() {
    const accessToken = sessionStorage.getItem('access_token');
    if (!accessToken) {
        redirectToAuth();
        return;
    }

    fetch(apiEndpoint, {
        method: 'GET',
        headers: {
            'Authorization': `Bearer ${accessToken}`
        }
    })
    .then(response => {
        if (!response.ok) {
            throw new Error('Network response was not ok');
        }
        return response.json();
    })
    .then(data => {
        console.log(data);
    })
    .catch(error => {
        console.error('Error:', error);
    });
}

// Check for access token on page load
window.onload = () => {
    const accessToken = parseAccessToken();
    if (accessToken) {
        apiCall();
    } else {
        redirectToAuth();
    }
};